-- Single-Foot Box Tap Run (single-foot-box-tap-run)
UPDATE coaching.exercise SET
  name = 'Single-Foot Box Tap Run',
  description = 'Single-Foot Box Tap Run is a ladder-focused exercise for precise foot placement and quick ground contacts without overstriding.',
  card_summary = 'Single-Foot Box Tap Run uses the ladder to build precise foot placement and quick ground contacts without overstriding. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.',
  coach_language = 'Primary phase: Movement Intelligence. Subrole: locomotion_sprint_mechanics. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.',
  athlete_language = 'Fast feet are only good if they are clean feet.',
  movement_family = 'Linear ladder rhythm',
  primary_phase_key = 'movement_intelligence',
  phase_subrole = 'locomotion_sprint_mechanics',
  primary_order_slot = 'ladder_linear_rhythm',
  participant_structure = 'individual',
  default_sets = 2,
  default_reps = 2,
  default_work_seconds = 15,
  default_rest_seconds = 30,
  est_seconds_per_set = 55,
  movement_requirements = '{"primary_joint_actions":["ankle_dorsiflexion","hip_flexion_extension","knee_drive","trunk_upright_posture"],"primary_tissues":["plantar_foot","calves","hip_flexors","glutes"],"breathing_demand":"natural rhythmic breathing","balance_demand":"dynamic balance over changing foot positions","coordination_demand":"rapid foot placement, rhythm, and spatial awareness","impact_level":1}'::jsonb,
  coaching_execution = '{"movement_description":"Single-Foot Box Tap Run uses the agility ladder as a visual target to train precise foot placement and quick ground contacts without overstriding. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Lay the agility ladder flat and remove tripping hazards.","Show one slow walk-through rep before speed is allowed.","Start tall with eyes forward, arms ready, and feet just outside the first box."],"execution_steps":["Step through the ladder using the assigned foot pattern.","Keep contacts light, posture tall, and arms coordinated with the feet.","Finish the ladder cleanly, decelerate under control, and walk back for the next rep."],"coach_cues":["Eyes up.","Fast but clean.","Step, do not stomp.","Own the pattern before speed."],"athlete_cues":["Stay tall.","Light feet.","Hit every box clean.","Slow down if your feet get messy."],"breathing_cues":["Breathe naturally; do not hold breath to move faster."],"quality_gate":["No missed boxes for one full pass","Posture stays tall","Speed increases only after the pattern is clean"],"common_faults":["Looking down the entire time","Skipping boxes unintentionally","Heavy flat-foot contacts","Torso folding or twisting to chase speed"],"stop_signs":["Tripping on the ladder","Repeated missed contacts","Athlete cannot decelerate after the finish"]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Acceleration starts","Change-of-direction drill","Jump or landing teaching","Sport-specific agility task"],"pairs_well_after":["Raise and mobility warm-up","Ankle pogo prep","A-march","Lateral shuffle basics"],"good_for_sessions":["general_warmup","sprint_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete is too fatigued to keep clean contacts","Ladder becomes a trip hazard or slides on the surface","Pain appears with the required foot, hop, or hand-support pattern"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=VE9K9w6rOmM","https://www.youtube.com/watch?v=4EC1HKM1fqA","https://www.youtube.com/watch?v=oxjC-0yuSHM","https://www.youtube.com/watch?v=B_bbBglPGHA"],"internal_notes":["Film one slow demonstration and one clean normal-speed rep from the front or diagonal angle.","Show the start position, full ladder pass, and deceleration/reset after the finish.","Keep YouTube links in mediaReferences, not internal notes, so Client view can embed them."]}'::jsonb,
  updated_at = now()
WHERE slug = 'single-foot-box-tap-run';

