-- Lateral Quick Step to Stick (lateral-quick-step-to-stick)
UPDATE coaching.exercise SET
  name = 'Lateral Quick Step to Stick',
  description = 'Lateral Quick Step to Stick is a ladder-focused exercise for quick lateral rhythm followed by a controlled stick and quiet landing.',
  card_summary = 'Lateral Quick Step to Stick uses the ladder to build quick lateral rhythm followed by a controlled stick and quiet landing. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.',
  coach_language = 'Primary phase: Resilience. Subrole: landing_braking_control. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.',
  athlete_language = 'Fast feet are only good if they are clean feet.',
  movement_family = 'Lateral brake ladder',
  primary_phase_key = 'resilience',
  phase_subrole = 'landing_braking_control',
  primary_order_slot = 'ladder_landing_control',
  participant_structure = 'individual',
  default_sets = 2,
  default_reps = 12,
  default_work_seconds = 20,
  default_rest_seconds = 45,
  est_seconds_per_set = 65,
  movement_requirements = '{"primary_joint_actions":["ankle_stiffness","knee_flexion_extension","hip_absorption","landing_brake"],"primary_tissues":["plantar_foot","achilles_calf_complex","quadriceps","glutes"],"breathing_demand":"natural breathing; no breath-holding","balance_demand":"single-leg or two-foot landing control","coordination_demand":"rhythmic contacts with quiet landings","impact_level":2,"landing_control_profile":{"surface_type":"flat non-slip training surface","amplitude":"low to moderate","stick_quality":"quiet landing, knee tracks over toes, two-second control when prescribed"}}'::jsonb,
  coaching_execution = '{"movement_description":"Lateral Quick Step to Stick uses the agility ladder as a visual target to train quick lateral rhythm followed by a controlled stick and quiet landing. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Place the ladder flat on a non-slip surface.","Begin just before the first box with knees soft and eyes forward.","Choose two-foot or single-leg stance exactly as prescribed."],"execution_steps":["Hop through the boxes using the pattern while keeping contacts quiet.","Land with foot, knee, and hip stacked; avoid knees diving inward.","Reset after the ladder or after each stick before the next rep."],"coach_cues":["Quiet feet.","Knees track over toes.","Stiff ankle, soft knee.","Stick means freeze."],"athlete_cues":["Land quiet.","Knees face your toes.","Freeze on the stick.","Spring off the ground, do not stomp."],"breathing_cues":["Exhale naturally on effort; avoid bracing so hard that breath stops."],"quality_gate":["Contacts stay quiet","Knee tracks well","Landing can be held for two seconds when required"],"common_faults":["Loud landings","Knee valgus","Hopping too far beyond the box","Extra steps after a stick"],"stop_signs":["Ankle, knee, or Achilles pain","Repeated knee collapse","Loud uncontrolled contacts"]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Acceleration starts","Change-of-direction drill","Jump or landing teaching","Sport-specific agility task"],"pairs_well_after":["Raise and mobility warm-up","Ankle pogo prep","A-march","Lateral shuffle basics"],"good_for_sessions":["general_warmup","landing_prep","control_landing"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete is too fatigued to keep clean contacts","Ladder becomes a trip hazard or slides on the surface","Pain appears with the required foot, hop, or hand-support pattern"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=_D-tsCyh-fA","https://www.youtube.com/watch?v=-gClX9YhYes","https://www.youtube.com/watch?v=33LWafmmuU4","https://www.youtube.com/watch?v=SMmT9WJrkAs"],"internal_notes":["Film one slow demonstration and one clean normal-speed rep from the front or diagonal angle.","Show the start position, full ladder pass, and deceleration/reset after the finish.","Keep YouTube links in mediaReferences, not internal notes, so Client view can embed them."]}'::jsonb,
  updated_at = now()
WHERE slug = 'lateral-quick-step-to-stick';

