-- Two-Foot Hop Each Box (two-foot-hop-each-box)
UPDATE coaching.exercise SET
  name = 'Two-Foot Hop Each Box',
  description = 'Two-Foot Hop Each Box is a ladder-focused exercise for basic elastic contacts and quiet two-foot landings through each box.',
  card_summary = 'Two-Foot Hop Each Box uses the ladder to build basic elastic contacts and quiet two-foot landings through each box. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.',
  coach_language = 'Primary phase: Movement Intelligence. Subrole: balance_coordination_rhythm. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.',
  athlete_language = 'Fast feet are only good if they are clean feet.',
  movement_family = 'Ladder hop family',
  primary_phase_key = 'movement_intelligence',
  phase_subrole = 'balance_coordination_rhythm',
  primary_order_slot = 'ladder_elastic_hops',
  participant_structure = 'individual',
  default_sets = 2,
  default_reps = 12,
  default_work_seconds = 20,
  default_rest_seconds = 45,
  est_seconds_per_set = 65,
  movement_requirements = '{"primary_joint_actions":["ankle_stiffness","knee_flexion_extension","hip_absorption","landing_brake"],"primary_tissues":["plantar_foot","achilles_calf_complex","quadriceps","glutes"],"breathing_demand":"natural breathing; no breath-holding","balance_demand":"dynamic two-foot balance","coordination_demand":"rhythmic contacts with quiet landings","impact_level":2}'::jsonb,
  coaching_execution = '{"movement_description":"Two-Foot Hop Each Box uses the agility ladder as a visual target to train basic elastic contacts and quiet two-foot landings through each box. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Place the ladder flat on a non-slip surface.","Begin just before the first box with knees soft and eyes forward.","Choose two-foot or single-leg stance exactly as prescribed."],"execution_steps":["Hop through the boxes using the pattern while keeping contacts quiet.","Land with foot, knee, and hip stacked; avoid knees diving inward.","Reset after the ladder or after each stick before the next rep."],"coach_cues":["Quiet feet.","Knees track over toes.","Stiff ankle, soft knee.","Stick means freeze."],"athlete_cues":["Land quiet.","Knees face your toes.","Freeze on the stick.","Spring off the ground, do not stomp."],"breathing_cues":["Exhale naturally on effort; avoid bracing so hard that breath stops."],"quality_gate":["Contacts stay quiet","Knee tracks well","Landing can be held for two seconds when required"],"common_faults":["Loud landings","Knee valgus","Hopping too far beyond the box","Extra steps after a stick"],"stop_signs":["Ankle, knee, or Achilles pain","Repeated knee collapse","Loud uncontrolled contacts"]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Acceleration starts","Change-of-direction drill","Jump or landing teaching","Sport-specific agility task"],"pairs_well_after":["Raise and mobility warm-up","Ankle pogo prep","A-march","Lateral shuffle basics"],"good_for_sessions":["general_warmup","landing_prep","control_landing"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete is too fatigued to keep clean contacts","Ladder becomes a trip hazard or slides on the surface","Pain appears with the required foot, hop, or hand-support pattern"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=33LWafmmuU4","https://www.youtube.com/watch?v=SMmT9WJrkAs","https://www.youtube.com/watch?v=5BeXtXkyv24","https://www.youtube.com/watch?v=cEoR7NxR8Xk"],"internal_notes":["Film one slow demonstration and one clean normal-speed rep from the front or diagonal angle.","Show the start position, full ladder pass, and deceleration/reset after the finish.","Keep YouTube links in mediaReferences, not internal notes, so Client view can embed them."]}'::jsonb,
  updated_at = now()
WHERE slug = 'two-foot-hop-each-box';

