  est_seconds_per_set = 65,
  movement_requirements = '{"primary_joint_actions":["ankle_stiffness","knee_flexion_extension","hip_absorption","landing_brake"],"primary_tissues":["plantar_foot","achilles_calf_complex","quadriceps","glutes"],"breathing_demand":"natural breathing; no breath-holding","balance_demand":"dynamic two-foot balance","coordination_demand":"rhythmic contacts with quiet landings","impact_level":2}'::jsonb,
  coaching_execution = '{"movement_description":"Lateral Two-Foot Hops uses the agility ladder as a visual target to train side-to-side two-foot elasticity and safe knee tracking. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Place the ladder flat on a non-slip surface.","Begin just before the first box with knees soft and eyes forward.","Choose two-foot or single-leg stance exactly as prescribed."],"execution_steps":["Hop through the boxes using the pattern while keeping contacts quiet.","Land with foot, knee, and hip stacked; avoid knees diving inward.","Reset after the ladder or after each stick before the next rep."],"coach_cues":["Quiet feet.","Knees track over toes.","Stiff ankle, soft knee.","Stick means freeze."],"athlete_cues":["Land quiet.","Knees face your toes.","Freeze on the stick.","Spring off the ground, do not stomp."],"breathing_cues":["Exhale naturally on effort; avoid bracing so hard that breath stops."],"quality_gate":["Contacts stay quiet","Knee tracks well","Landing can be held for two seconds when required"],"common_faults":["Loud landings","Knee valgus","Hopping too far beyond the box","Extra steps after a stick"],"stop_signs":["Ankle, knee, or Achilles pain","Repeated knee collapse","Loud uncontrolled contacts"]}'::jsonb,
