UPDATE coaching.exercise SET
  name = 'Pogo In-In Out-Out',
  description = 'Pogo In-In Out-Out is a ladder-focused exercise for rapid ankle-dominant pogos under a precise in-in/out-out foot pattern.',
  card_summary = 'Pogo In-In Out-Out uses the ladder to build rapid ankle-dominant pogos under a precise in-in/out-out foot pattern. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.',
  coach_language = 'Primary phase: Output. Subrole: elastic_stiffness_plyometric_rudiments. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.',
  athlete_language = 'Fast feet are only good if they are clean feet.',
  movement_family = 'Ladder hop family',
  primary_phase_key = 'output',
  phase_subrole = 'elastic_stiffness_plyometric_rudiments',
  primary_order_slot = 'ladder_elastic_output',
  participant_structure = 'individual',
  default_sets = 4,
  default_reps = 2,
  default_work_seconds = 8,
  default_rest_seconds = 75,
  est_seconds_per_set = 95,
  movement_requirements = '{"primary_joint_actions":["ankle_stiffness","knee_flexion_extension","hip_absorption","landing_brake"],"primary_tissues":["plantar_foot","achilles_calf_complex","quadriceps","glutes"],"breathing_demand":"natural breathing; no breath-holding","balance_demand":"dynamic two-foot balance","coordination_demand":"rhythmic contacts with quiet landings","impact_level":3}'::jsonb,
  coaching_execution = '{"movement_description":"Pogo In-In Out-Out uses the agility ladder as a visual target to train rapid ankle-dominant pogos under a precise in-in/out-out foot pattern. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Place the ladder flat on a non-slip surface.","Begin just before the first box with knees soft and eyes forward.","Choose two-foot or single-leg stance exactly as prescribed."],"execution_steps":["Hop through the boxes using the pattern while keeping contacts quiet.","Land with foot, knee, and hip stacked; avoid knees diving inward.","Reset after the ladder or after each stick before the next rep."],"coach_cues":["Quiet feet.","Knees track over toes.","Stiff ankle, soft knee.","Stick means freeze."],"athlete_cues":["Land quiet.","Knees face your toes.","Freeze on the stick.","Spring off the ground, do not stomp."],"breathing_cues":["Exhale naturally on effort; avoid bracing so hard that breath stops."],"quality_gate":["Contacts stay quiet","Knee tracks well","Landing can be held for two seconds when required"],"common_faults":["Loud landings","Knee valgus","Hopping too far beyond the box","Extra steps after a stick"],"stop_signs":["Ankle, knee, or Achilles pain","Repeated knee collapse","Loud uncontrolled contacts"]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Acceleration starts","Change-of-direction drill","Jump or landing teaching","Sport-specific agility task"],"pairs_well_after":["Raise and mobility warm-up","Ankle pogo prep","A-march","Lateral shuffle basics"],"good_for_sessions":["general_warmup","sprint_prep","landing_prep","control_landing"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete is too fatigued to keep clean contacts","Ladder becomes a trip hazard or slides on the surface","Pain appears with the required foot, hop, or hand-support pattern"]}'::jsonb,
