-- Partner Tag Ladder Exit (partner-tag-ladder-exit)
UPDATE coaching.exercise SET
  name = 'Partner Tag Ladder Exit',
  description = 'Partner Tag Ladder Exit is a ladder-focused exercise for perform clean ladder contacts then exit to chase or evade on a short cue.',
  card_summary = 'Partner Tag Ladder Exit uses the ladder to build perform clean ladder contacts then exit to chase or evade on a short cue. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.',
  coach_language = 'Primary phase: Output. Subrole: reactive_agility_tumbling_output. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.',
  athlete_language = 'Fast feet are only good if they are clean feet.',
  movement_family = 'Partner reactive ladder',
  primary_phase_key = 'output',
  phase_subrole = 'reactive_agility_tumbling_output',
  primary_order_slot = 'ladder_reactive_exit',
  participant_structure = 'pairs',
  default_sets = 4,
  default_reps = 2,
  default_work_seconds = 8,
  default_rest_seconds = 75,
  est_seconds_per_set = 95,
  movement_requirements = '{"primary_joint_actions":["ankle_dorsiflexion","hip_flexion_extension","knee_drive","trunk_upright_posture"],"primary_tissues":["plantar_foot","calves","hip_flexors","glutes"],"breathing_demand":"natural rhythmic breathing","balance_demand":"dynamic balance over changing foot positions","coordination_demand":"rapid foot placement, rhythm, and spatial awareness","impact_level":2,"setup_metadata":{"ladder_layout":"flat ladder with 5-yard acceleration lane after final box","approach_speed":"controlled through ladder, aggressive on exit","rep_cap":"stop when exit speed drops or foot contacts become inaccurate"},"reactive_output_profile":{"stimulus_type":"coach, partner, color, number, or ball cue","decision_count":"1-3 options based on athlete level","amplitude_cap":"short ladder pass only; no fatigue chase"}}'::jsonb,
  coaching_execution = '{"movement_description":"Partner Tag Ladder Exit uses the agility ladder as a visual target to train perform clean ladder contacts then exit to chase or evade on a short cue. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Lay the agility ladder flat and remove tripping hazards.","Show one slow walk-through rep before speed is allowed.","Start tall with eyes forward, arms ready, and feet just outside the first box."],"execution_steps":["Step through the ladder using the assigned foot pattern.","Keep contacts light, posture tall, and arms coordinated with the feet.","Finish the ladder cleanly, decelerate under control, and walk back for the next rep."],"coach_cues":["Eyes up.","Fast but clean.","Step, do not stomp.","Own the pattern before speed."],"athlete_cues":["Stay tall.","Light feet.","Hit every box clean.","Slow down if your feet get messy."],"breathing_cues":["Breathe naturally; do not hold breath to move faster."],"quality_gate":["No missed boxes for one full pass","Posture stays tall","Speed increases only after the pattern is clean"],"common_faults":["Looking down the entire time","Skipping boxes unintentionally","Heavy flat-foot contacts","Torso folding or twisting to chase speed"],"stop_signs":["Tripping on the ladder","Repeated missed contacts","Athlete cannot decelerate after the finish"]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Acceleration starts","Change-of-direction drill","Jump or landing teaching","Sport-specific agility task"],"pairs_well_after":["Raise and mobility warm-up","Ankle pogo prep","A-march","Lateral shuffle basics"],"good_for_sessions":["general_warmup","sprint_prep","deceleration"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete is too fatigued to keep clean contacts","Ladder becomes a trip hazard or slides on the surface","Pain appears with the required foot, hop, or hand-support pattern"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=wnc-USTRncg","https://www.youtube.com/watch?v=aWmakR6Xl-k","https://www.youtube.com/watch?v=67XP-AekUoA","https://www.youtube.com/watch?v=4taYjKlmihU"],"internal_notes":["Film one slow demonstration and one clean normal-speed rep from the front or diagonal angle.","Show the start position, full ladder pass, and deceleration/reset after the finish.","Keep YouTube links in mediaReferences, not internal notes, so Client view can embed them."]}'::jsonb,
  updated_at = now()
WHERE slug = 'partner-tag-ladder-exit';

