-- Bear Crawl Ladder (bear-crawl-ladder)
UPDATE coaching.exercise SET
  name = 'Bear Crawl Ladder',
  description = 'Bear Crawl Ladder is a ladder-focused exercise for contralateral crawling rhythm, wrist/shoulder resilience, and trunk control.',
  card_summary = 'Bear Crawl Ladder uses the ladder to build contralateral crawling rhythm, wrist/shoulder resilience, and trunk control. Best used as a crisp, low-volume skill or power exposure rather than a fatigue circuit.',
  coach_language = 'Primary phase: Resilience. Subrole: scapular_wrist_hand_support_resilience. Treat the ladder as a constraint for precision; progress speed only after clean rhythm, posture, and spacing.',
  athlete_language = 'Fast feet are only good if they are clean feet.',
  movement_family = 'Hand support ladder',
  primary_phase_key = 'resilience',
  phase_subrole = 'scapular_wrist_hand_support_resilience',
  primary_order_slot = 'ladder_hand_support',
  participant_structure = 'individual',
  default_sets = 2,
  default_reps = 1,
  default_work_seconds = 20,
  default_rest_seconds = 45,
  est_seconds_per_set = 70,
  movement_requirements = '{"primary_joint_actions":["shoulder_flexion","scapular_protraction","wrist_extension","trunk_anti_rotation"],"primary_tissues":["shoulder_complex","wrist_flexors_extensors","anterior_core"],"breathing_demand":"controlled nasal breathing under trunk tension","balance_demand":"quadruped or plank base with hand-foot coordination","coordination_demand":"contralateral sequencing and trunk stiffness","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Bear Crawl Ladder uses the agility ladder as a visual target to train contralateral crawling rhythm, wrist/shoulder resilience, and trunk control. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Place the agility ladder flat and clear space around it.","Start in a strong bear crawl or plank position with hands near the first box.","Brace the trunk before moving; spread fingers and press the floor away."],"execution_steps":["Move hands, or hands and feet, through each ladder box using the assigned pattern.","Keep hips quiet and shoulders stacked over strong hands.","Finish the ladder, reset posture, and walk back before the next rep."],"coach_cues":["Push the floor away.","Quiet hips.","Small clean hand steps.","Move like a table, not a snake."],"athlete_cues":["Strong hands.","Quiet hips.","Small steps.","Freeze if your belly drops."],"breathing_cues":["Breathe behind the brace; do not hold breath through the whole ladder."],"quality_gate":["No low-back sag","Hands hit boxes cleanly","Athlete can stop instantly without collapsing"],"common_faults":["Hips rocking side to side","Sagging low back","Hands landing outside the target boxes","Rushing until shoulder position collapses"],"stop_signs":["Wrist pain","Shoulder pinching","Loss of plank/bear position for more than one step"]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Acceleration starts","Change-of-direction drill","Jump or landing teaching","Sport-specific agility task"],"pairs_well_after":["Raise and mobility warm-up","Ankle pogo prep","A-march","Lateral shuffle basics"],"good_for_sessions":["general_warmup","crawling_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete is too fatigued to keep clean contacts","Ladder becomes a trip hazard or slides on the surface","Pain appears with the required foot, hop, or hand-support pattern"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=c3GvRkiI8xc","https://www.youtube.com/watch?v=8BvRTDlbEsE","https://www.youtube.com/watch?v=mVEY_9b6gsk","https://www.youtube.com/watch?v=l9bqhv6jToQ"],"internal_notes":["Film one slow demonstration and one clean normal-speed rep from the front or diagonal angle.","Show the start position, full ladder pass, and deceleration/reset after the finish.","Keep YouTube links in mediaReferences, not internal notes, so Client view can embed them."]}'::jsonb,
  updated_at = now()
WHERE slug = 'bear-crawl-ladder';

