  movement_requirements = '{"primary_joint_actions":["shoulder_flexion","scapular_protraction","wrist_extension","trunk_anti_rotation"],"primary_tissues":["shoulder_complex","wrist_flexors_extensors","anterior_core"],"breathing_demand":"controlled nasal breathing under trunk tension","balance_demand":"quadruped or plank base with hand-foot coordination","coordination_demand":"contralateral sequencing and trunk stiffness","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Plank Walk Ladder uses the agility ladder as a visual target to train straight-arm plank hand steps with trunk stiffness and shoulder control. The athlete moves through the boxes with clean contacts, controlled posture, and enough rest to keep every rep crisp.","setup":["Place the agility ladder flat and clear space around it.","Start in a strong bear crawl or plank position with hands near the first box.","Brace the trunk before moving; spread fingers and press the floor away."],"execution_steps":["Move hands, or hands and feet, through each ladder box using the assigned pattern.","Keep hips quiet and shoulders stacked over strong hands.","Finish the ladder, reset posture, and walk back before the next rep."],"coach_cues":["Push the floor away.","Quiet hips.","Small clean hand steps.","Move like a table, not a snake."],"athlete_cues":["Strong hands.","Quiet hips.","Small steps.","Freeze if your belly drops."],"breathing_cues":["Breathe behind the brace; do not hold breath through the whole ladder."],"quality_gate":["No low-back sag","Hands hit boxes cleanly","Athlete can stop instantly without collapsing"],"common_faults":["Hips rocking side to side","Sagging low back","Hands landing outside the target boxes","Rushing until shoulder position collapses"],"stop_signs":["Wrist pain","Shoulder pinching","Loss of plank/bear position for more than one step"]}'::jsonb,
