-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for ladder rhythm, sprint mechanics, lateral control, elastic hops, reactive decisions, and hand-support progressions.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('one-in-ladder-run', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape clean single-contact foot rhythm, posture, and sprint-like front-side mechanics without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under locomotion_sprint_mechanics: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('two-in-quick-run', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape rapid alternating foot contacts while keeping hips tall and shoulders quiet without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under locomotion_sprint_mechanics: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('high-knee-a-march-ladder', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape march timing, knee lift, ankle dorsiflexion, and tall sprint posture without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under locomotion_sprint_mechanics: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('a-skip-through-ladder', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape skip rhythm, elastic foot strike, and coordinated arm-leg timing without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under locomotion_sprint_mechanics: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('straight-leg-ankling-ladder', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape low-amplitude ankle stiffness and front-side foot strike awareness without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under locomotion_sprint_mechanics: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('forward-in-in-out-out', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape basic coordination under a repeatable in-in/out-out constraint without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('single-foot-box-tap-run', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape precise foot placement and quick ground contacts without overstriding without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under locomotion_sprint_mechanics: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('forward-backward-quick-feet', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape forward and retreating rhythm with posture preserved during direction changes without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('two-up-one-back-ladder-run', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape sequencing memory, foot speed, and controlled braking between boxes without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('wide-narrow-ladder-run', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape stance width control and hip-foot alignment during quick contacts without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('lateral-one-in-shuffle', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape sideways foot rhythm, athletic base, and hip-knee-ankle alignment without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('lateral-two-in-shuffle', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape controlled lateral cadence with both feet entering each box without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('lateral-in-in-out-out', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape lateral foot separation, re-centering, and coordination under speed without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('lateral-scissor-step-ladder', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape quick exchange of lead/trail foot without losing torso position without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('lateral-crossover-step-ladder', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape crossover coordination, hip rotation control, and lateral travel skill without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('carioca-ladder', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape hip dissociation, trunk control, and coordinated crossover footwork without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('lateral-icky-shuffle', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape lateral rhythm, inside-outside foot placement, and re-acceleration timing without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('sideways-two-up-one-back', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape sideways sequencing and controlled repositioning without crossing feet unintentionally without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('lateral-base-rotation-ladder', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape rotate the hips and base while the trunk stays organized without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('lateral-quick-step-to-stick', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape quick lateral rhythm followed by a controlled stick and quiet landing without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Resilience under landing_braking_control: it builds control, braking quality, and tissue tolerance rather than max speed.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not race the drill. The target is control under the ladder constraint; speed is only added after clean positions are repeatable.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('icky-shuffle', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape classic inside-outside ladder rhythm and coordinated weight shift without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('reverse-icky-shuffle', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape backward sequencing, spatial awareness, and rhythm under a reverse constraint without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('forward-icky-to-sprint-exit', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape turn a clean ladder rhythm into a sharp first step and acceleration exit without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Output under acceleration_start_speed: the drill must be low-volume, high-intent, and fully rested so the exit or elastic contact is fast rather than tired.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not bury this after conditioning or use repeated sloppy attempts. Tired reps become conditioning, not speed or power.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('crossover-icky-shuffle', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape cross-body foot placement and hip rotation while keeping eyes up without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('ali-shuffle-ladder', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape front-back foot exchange, rhythm, and light elastic contacts without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('ali-shuffle-hip-switch', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape hip switch timing and fast front-back exchange with controlled trunk without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('skier-slalom-steps', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape rhythmic side-to-side foot placement and elastic lateral stiffness without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
  ('in-out-turn-and-open-hips', 'The ladder creates clear visual boxes that constrain stride length, contact location, and rhythm. This lets coaches shape open the hips, turn the base, and re-square without losing posture without heavy fatigue, while giving athletes immediate feedback when they miss a box or lose posture.', 'Belongs in Movement Intelligence under balance_coordination_rhythm: it teaches rhythm and coordination while the nervous system is fresh, before fatigue turns learning into conditioning.', 'Early in the session after Raise/Mobilize work; pair with sprint mechanics, COD teaching, hopping prep, or hand-support prep depending on the pattern.', 'Do not turn this into a long conditioning circuit. If posture, rhythm, or foot accuracy breaks down, the drill has outlived its purpose for that set.', 'Scale first by pattern complexity, then by speed, then by impact or reactive demand. Never progress a ladder drill by simply making it messier or longer.'),
